import{_ as l,o as i,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"Python 生态","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/backend/python-stack.md","filePath":"tech-system/backend/python-stack.md"}'),o={name:"tech-system/backend/python-stack.md"};function t(n,a,s,h,d,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="python-生态" tabindex="-1">Python 生态 <a class="header-anchor" href="#python-生态" aria-label="Permalink to “Python 生态”">​</a></h1><p>Python 以其简洁优雅的语法和丰富的生态系统，成为后端开发、数据科学、AI应用的重要语言。</p><h2 id="一、python-基础快速入门" tabindex="-1">一、Python 基础快速入门 <a class="header-anchor" href="#一、python-基础快速入门" aria-label="Permalink to “一、Python 基础快速入门”">​</a></h2><h3 id="_1-1-语法与核心概念" tabindex="-1">1.1 语法与核心概念 <a class="header-anchor" href="#_1-1-语法与核心概念" aria-label="Permalink to “1.1 语法与核心概念”">​</a></h3><ul><li><strong>环境与版本</strong>：推荐直接使用 <code>uv</code> 管理 Python 版本和虚拟环境（见文末常用工具）。</li><li><strong>基本语法</strong>：缩进（4 空格）、注释（<code>#</code>）、<code>if/for/while</code>、<code>def</code>、<code>class</code>。</li><li><strong>数据类型</strong>：<code>int / float / bool / str / list / tuple / dict / set</code>。</li><li><strong>控制流程</strong>：条件判断、循环、<code>break/continue</code>、<code>enumerate</code>、<code>range</code>。</li><li><strong>函数</strong>：位置参数、关键字参数、默认参数、<code>*args / **kwargs</code>。</li><li><strong>面向对象</strong>：类定义、构造函数 <code>__init__</code>、继承、<code>super()</code>、魔术方法 <code>__str__ / __repr__</code>。</li></ul><h3 id="_1-2-标准库-必须熟悉的几个" tabindex="-1">1.2 标准库（必须熟悉的几个） <a class="header-anchor" href="#_1-2-标准库-必须熟悉的几个" aria-label="Permalink to “1.2 标准库（必须熟悉的几个）”">​</a></h3><ul><li><strong>数据结构</strong>：<code>collections</code>（<code>deque、Counter、defaultdict、namedtuple</code>）。</li><li><strong>文件与路径</strong>：<code>open</code>、<code>with</code> 上下文管理、<code>pathlib.Path</code>。</li><li><strong>日期时间</strong>：<code>datetime</code>、<code>time</code>。</li><li><strong>序列化</strong>：<code>json</code>、<code>pickle</code>（了解安全问题）。</li><li><strong>并发编程</strong>：<code>threading</code>、<code>concurrent.futures</code>、<code>asyncio</code>（简单异步任务）。</li><li><strong>网络请求（标准库）</strong>：<code>urllib.request</code>（真实项目多用第三方 <code>requests</code>）。</li></ul><h3 id="_1-3-基础练手建议" tabindex="-1">1.3 基础练手建议 <a class="header-anchor" href="#_1-3-基础练手建议" aria-label="Permalink to “1.3 基础练手建议”">​</a></h3><ul><li>写 3～5 个小脚本： <ul><li>批量重命名文件、简单日志分析、读取 CSV/JSON 并输出统计结果。</li><li>调用 HTTP 接口拉取数据并保存到本地。</li><li>把你 Java 面试库里的某个目录扫描成一个“目录索引”JSON。</li></ul></li></ul><h2 id="web-框架" tabindex="-1">Web 框架 <a class="header-anchor" href="#web-框架" aria-label="Permalink to “Web 框架”">​</a></h2><h3 id="django" tabindex="-1">Django <a class="header-anchor" href="#django" aria-label="Permalink to “Django”">​</a></h3><ul><li><strong>MTV 架构</strong>: Model、Template、View分离</li><li><strong>ORM</strong>: 模型定义、查询API、迁移系统</li><li><strong>Admin</strong>: 自动后台管理界面</li><li><strong>认证系统</strong>: 用户模型、权限管理、会话</li></ul><h3 id="flask" tabindex="-1">Flask <a class="header-anchor" href="#flask" aria-label="Permalink to “Flask”">​</a></h3><ul><li><strong>微框架</strong>: 核心简单、可扩展性强</li><li><strong>路由系统</strong>: URL规则、视图函数、蓝图</li><li><strong>模板引擎</strong>: Jinja2、模板继承、宏</li><li><strong>扩展生态</strong>: Flask-SQLAlchemy、Flask-Migrate</li></ul><h3 id="fastapi" tabindex="-1">FastAPI <a class="header-anchor" href="#fastapi" aria-label="Permalink to “FastAPI”">​</a></h3><ul><li><strong>异步支持</strong>: async/await、并发处理</li><li><strong>类型提示</strong>: Pydantic、自动API文档</li><li><strong>依赖注入</strong>: 请求依赖、路径依赖</li><li><strong>性能优化</strong>: Uvicorn、自动序列化</li></ul><h3 id="其他框架" tabindex="-1">其他框架 <a class="header-anchor" href="#其他框架" aria-label="Permalink to “其他框架”">​</a></h3><ul><li><strong>Tornado</strong>: 异步Web框架、高并发处理</li><li><strong>Sanic</strong>: 基于uvloop的异步框架</li><li><strong>Bottle</strong>: 单文件Web框架</li></ul><h2 id="数据处理" tabindex="-1">数据处理 <a class="header-anchor" href="#数据处理" aria-label="Permalink to “数据处理”">​</a></h2><h3 id="numpy" tabindex="-1">NumPy <a class="header-anchor" href="#numpy" aria-label="Permalink to “NumPy”">​</a></h3><ul><li><strong>多维数组</strong>: ndarray、数组操作、广播</li><li><strong>数学函数</strong>: 线性代数、随机数、统计</li><li><strong>性能优化</strong>: 向量化计算、内存布局</li></ul><h3 id="pandas" tabindex="-1">Pandas <a class="header-anchor" href="#pandas" aria-label="Permalink to “Pandas”">​</a></h3><ul><li><strong>DataFrame</strong>: 数据结构、索引、分层索引</li><li><strong>数据操作</strong>: 选择、过滤、聚合、合并</li><li><strong>时间序列</strong>: 日期处理、重采样、时区</li><li><strong>数据清洗</strong>: 缺失值处理、异常值检测</li></ul><h3 id="数据可视化" tabindex="-1">数据可视化 <a class="header-anchor" href="#数据可视化" aria-label="Permalink to “数据可视化”">​</a></h3><ul><li><strong>Matplotlib</strong>: 基础绘图、子图、样式设置</li><li><strong>Seaborn</strong>: 统计绘图、主题样式、美化</li><li><strong>Plotly</strong>: 交互式图表、Web集成</li></ul><h2 id="数据库集成" tabindex="-1">数据库集成 <a class="header-anchor" href="#数据库集成" aria-label="Permalink to “数据库集成”">​</a></h2><h3 id="sqlalchemy" tabindex="-1">SQLAlchemy <a class="header-anchor" href="#sqlalchemy" aria-label="Permalink to “SQLAlchemy”">​</a></h3><ul><li><strong>ORM</strong>: 模型定义、关系映射、查询API</li><li><strong>Core</strong>: SQL表达式、连接池、事务</li><li><strong>迁移</strong>: Alembic、版本控制</li></ul><h3 id="django-orm" tabindex="-1">Django ORM <a class="header-anchor" href="#django-orm" aria-label="Permalink to “Django ORM”">​</a></h3><ul><li><strong>模型</strong>: 字段类型、关系、外键</li><li><strong>查询</strong>: QuerySet API、聚合函数</li><li><strong>管理器</strong>: 自定义查询方法</li></ul><h3 id="nosql" tabindex="-1">NoSQL <a class="header-anchor" href="#nosql" aria-label="Permalink to “NoSQL”">​</a></h3><ul><li><strong>MongoDB</strong>: PyMongo、ODM (MongoEngine)</li><li><strong>Redis</strong>: redis-py、数据类型操作</li><li><strong>Elasticsearch</strong>: elasticsearch-py、DSL查询</li></ul><h2 id="异步编程" tabindex="-1">异步编程 <a class="header-anchor" href="#异步编程" aria-label="Permalink to “异步编程”">​</a></h2><h3 id="asyncio" tabindex="-1">asyncio <a class="header-anchor" href="#asyncio" aria-label="Permalink to “asyncio”">​</a></h3><ul><li><strong>协程</strong>: async def、await、asyncio.run</li><li><strong>任务管理</strong>: Task、Future、事件循环</li><li><strong>并发模式</strong>: gather、wait、as_completed</li></ul><h3 id="aiohttp" tabindex="-1">aiohttp <a class="header-anchor" href="#aiohttp" aria-label="Permalink to “aiohttp”">​</a></h3><ul><li><strong>异步HTTP</strong>: 客户端、服务端</li><li><strong>WebSocket</strong>: 双向通信、实时应用</li><li><strong>中间件</strong>: 请求处理、错误处理</li></ul><h3 id="fastapi-异步" tabindex="-1">FastAPI 异步 <a class="header-anchor" href="#fastapi-异步" aria-label="Permalink to “FastAPI 异步”">​</a></h3><ul><li><strong>异步视图</strong>: async def endpoints</li><li><strong>依赖注入</strong>: 异步依赖、上下文管理</li><li><strong>后台任务</strong>: BackgroundTasks</li></ul><h2 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to “测试”">​</a></h2><h3 id="unittest" tabindex="-1">unittest <a class="header-anchor" href="#unittest" aria-label="Permalink to “unittest”">​</a></h3><ul><li><strong>测试用例</strong>: TestCase、setUp/tearDown</li><li><strong>断言方法</strong>: assertEqual、assertRaises</li><li><strong>测试发现</strong>: 自动发现、测试运行器</li></ul><h3 id="pytest" tabindex="-1">pytest <a class="header-anchor" href="#pytest" aria-label="Permalink to “pytest”">​</a></h3><ul><li><strong>简洁语法</strong>: 函数式测试、fixture</li><li><strong>参数化</strong>: @pytest.mark.parametrize</li><li><strong>插件生态</strong>: pytest-django、pytest-asyncio</li></ul><h3 id="其他测试" tabindex="-1">其他测试 <a class="header-anchor" href="#其他测试" aria-label="Permalink to “其他测试”">​</a></h3><ul><li><strong>doctest</strong>: 文档字符串测试</li><li><strong>hypothesis</strong>: 属性测试、数据生成</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="代码优化" tabindex="-1">代码优化 <a class="header-anchor" href="#代码优化" aria-label="Permalink to “代码优化”">​</a></h3><ul><li><strong>性能分析</strong>: cProfile、line_profiler</li><li><strong>内存优化</strong>: memory_profiler、gc模块</li><li><strong>并发优化</strong>: multiprocessing、threading</li></ul><h3 id="cython" tabindex="-1">Cython <a class="header-anchor" href="#cython" aria-label="Permalink to “Cython”">​</a></h3><ul><li><strong>类型声明</strong>: cdef、静态类型</li><li><strong>编译优化</strong>: 编译为C扩展</li><li><strong>性能提升</strong>: 数值计算加速</li></ul><h3 id="numba" tabindex="-1">Numba <a class="header-anchor" href="#numba" aria-label="Permalink to “Numba”">​</a></h3><ul><li><strong>JIT编译</strong>: @jit装饰器</li><li><strong>向量化</strong>: @vectorize</li><li><strong>并行计算</strong>: @parallel</li></ul><h2 id="部署与运维" tabindex="-1">部署与运维 <a class="header-anchor" href="#部署与运维" aria-label="Permalink to “部署与运维”">​</a></h2><h3 id="wsgi-asgi" tabindex="-1">WSGI/ASGI <a class="header-anchor" href="#wsgi-asgi" aria-label="Permalink to “WSGI/ASGI”">​</a></h3><ul><li><strong>WSGI</strong>: Gunicorn、uWSGI、部署配置</li><li><strong>ASGI</strong>: Uvicorn、Hypercorn，部署 FastAPI 等异步服务</li></ul><h3 id="容器化" tabindex="-1">容器化 <a class="header-anchor" href="#容器化" aria-label="Permalink to “容器化”">​</a></h3><ul><li><strong>Docker</strong>: 多阶段构建、Python 镜像优化（使用 <code>python:slim</code>、<code>uv</code> 官方镜像等）。</li><li><strong>Kubernetes</strong>: Deployment、ConfigMap（中高级可选）。</li></ul><h3 id="云部署" tabindex="-1">云部署 <a class="header-anchor" href="#云部署" aria-label="Permalink to “云部署”">​</a></h3><ul><li>轻量：Railway / Render / Fly.io / 部分国内平台——适合个人小服务。</li><li>传统云：阿里云/腾讯云轻量服务器 + Docker 部署。</li></ul><h2 id="数据科学" tabindex="-1">数据科学 <a class="header-anchor" href="#数据科学" aria-label="Permalink to “数据科学”">​</a></h2><h3 id="scipy" tabindex="-1">SciPy <a class="header-anchor" href="#scipy" aria-label="Permalink to “SciPy”">​</a></h3><ul><li><strong>科学计算</strong>: 积分、优化、插值</li><li><strong>信号处理</strong>: 滤波、频谱分析</li><li><strong>图像处理</strong>: 图像变换、形态学</li></ul><h3 id="scikit-learn" tabindex="-1">Scikit-learn <a class="header-anchor" href="#scikit-learn" aria-label="Permalink to “Scikit-learn”">​</a></h3><ul><li><strong>机器学习</strong>: 分类、回归、聚类</li><li><strong>模型评估</strong>: 交叉验证、指标计算</li><li><strong>预处理</strong>: 特征工程、数据标准化</li></ul><h3 id="jupyter" tabindex="-1">Jupyter <a class="header-anchor" href="#jupyter" aria-label="Permalink to “Jupyter”">​</a></h3><ul><li><strong>交互式计算</strong>: Notebook、魔法命令</li><li><strong>可视化</strong>: matplotlib集成、widgets</li><li><strong>分享</strong>: nbconvert、JupyterHub</li></ul><h2 id="web-爬虫" tabindex="-1">Web 爬虫 <a class="header-anchor" href="#web-爬虫" aria-label="Permalink to “Web 爬虫”">​</a></h2><h3 id="requests" tabindex="-1">Requests <a class="header-anchor" href="#requests" aria-label="Permalink to “Requests”">​</a></h3><ul><li><strong>HTTP请求</strong>: GET/POST、会话管理</li><li><strong>认证</strong>: Basic Auth、OAuth</li><li><strong>高级功能</strong>: 代理、SSL验证</li></ul><h3 id="beautiful-soup" tabindex="-1">Beautiful Soup <a class="header-anchor" href="#beautiful-soup" aria-label="Permalink to “Beautiful Soup”">​</a></h3><ul><li><strong>HTML解析</strong>: 标签选择、属性获取</li><li><strong>CSS选择器</strong>: select()、find_all()</li><li><strong>文档遍历</strong>: 父子关系、兄弟节点</li></ul><h3 id="scrapy" tabindex="-1">Scrapy <a class="header-anchor" href="#scrapy" aria-label="Permalink to “Scrapy”">​</a></h3><ul><li><strong>爬虫框架</strong>: Spider、Item Pipeline</li><li><strong>中间件</strong>: 下载中间件、爬虫中间件</li><li><strong>扩展</strong>: 分布式爬取、自动限速</li></ul><h2 id="api-开发" tabindex="-1">API 开发 <a class="header-anchor" href="#api-开发" aria-label="Permalink to “API 开发”">​</a></h2><h3 id="rest-api" tabindex="-1">REST API <a class="header-anchor" href="#rest-api" aria-label="Permalink to “REST API”">​</a></h3><ul><li><strong>设计原则</strong>: RESTful、HTTP方法、状态码</li><li><strong>序列化</strong>: JSON、XML、自定义格式</li><li><strong>文档</strong>: Swagger/OpenAPI、自动生成</li></ul><h3 id="graphql" tabindex="-1">GraphQL <a class="header-anchor" href="#graphql" aria-label="Permalink to “GraphQL”">​</a></h3><ul><li><strong>Schema</strong>: 类型定义、查询语言</li><li><strong>解析器</strong>: 数据获取、字段解析</li><li><strong>客户端</strong>: Apollo Client、Relay</li></ul><h3 id="websocket" tabindex="-1">WebSocket <a class="header-anchor" href="#websocket" aria-label="Permalink to “WebSocket”">​</a></h3><ul><li><strong>实时通信</strong>: Socket.IO、WebSocket协议</li><li><strong>广播</strong>: 房间管理、命名空间</li><li><strong>扩展</strong>: 认证、错误处理</li></ul><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to “安全”">​</a></h2><h3 id="web安全" tabindex="-1">Web安全 <a class="header-anchor" href="#web安全" aria-label="Permalink to “Web安全”">​</a></h3><ul><li><strong>输入验证</strong>: 数据清洗、类型检查</li><li><strong>认证</strong>: JWT、OAuth2、会话管理</li><li><strong>授权</strong>: 角色权限、对象级权限</li></ul><h3 id="数据安全" tabindex="-1">数据安全 <a class="header-anchor" href="#数据安全" aria-label="Permalink to “数据安全”">​</a></h3><ul><li><strong>加密</strong>: hashlib、cryptography</li><li><strong>密码安全</strong>: bcrypt、scrypt</li><li><strong>SSL/TLS</strong>: HTTPS、证书验证</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="代码规范" tabindex="-1">代码规范 <a class="header-anchor" href="#代码规范" aria-label="Permalink to “代码规范”">​</a></h3><ul><li><strong>PEP 8</strong>: 代码风格、命名约定</li><li><strong>类型提示</strong>: typing模块、mypy</li><li><strong>文档</strong>: docstring、Sphinx</li></ul><h3 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to “项目结构”">​</a></h3><ul><li><strong>包结构</strong>: <strong>init</strong>.py、相对导入</li><li><strong>配置管理</strong>: 环境变量、配置文件</li><li><strong>日志</strong>: logging模块、结构化日志</li></ul><h3 id="依赖管理与-uv-常用操作" tabindex="-1">依赖管理与 <code>uv</code> 常用操作 <a class="header-anchor" href="#依赖管理与-uv-常用操作" aria-label="Permalink to “依赖管理与 uv 常用操作”">​</a></h3><ul><li><strong>传统方式</strong>： <ul><li><code>venv</code> + <code>pip</code> + <code>requirements.txt</code>。</li><li>常见问题：环境多、依赖冲突、安装速度慢。</li></ul></li><li><strong>推荐：使用 <code>uv</code> 统一管理 Python 与包（Rust 写的高速工具）</strong>： <ul><li>安装（Windows）： <ul><li>参考官方文档，一般是一条安装脚本或安装包（可写一篇单独操作笔记）。</li></ul></li><li>常用命令（记住这几个够用）： <ul><li><code>uv init</code>：初始化一个 Python 项目（自动创建虚拟环境和配置）。</li><li><code>uv venv</code>：在当前目录创建虚拟环境。</li><li><code>uv run main.py</code>：在虚拟环境中运行脚本（自动处理依赖）。</li><li><code>uv add fastapi uvicorn</code>：安装依赖并写入配置。</li><li><code>uv remove fastapi</code>：移除依赖。</li><li><code>uv sync</code>：根据配置文件同步安装依赖（类似 <code>npm install</code>）。</li></ul></li><li>对你来说的好处： <ul><li>不用手动管理 <code>pip + venv</code> 细节，创建/切换项目更快。</li><li>安装第三方包速度更快，适合频繁试验 AI / 爬虫 / Web 小项目。</li></ul></li></ul></li></ul>',93)])])}const b=l(o,[["render",t]]);export{u as __pageData,b as default};
